const userMessage = $('Telegram Trigger').item.json.message.text || '';
const chatId = $('Telegram Trigger').item.json.message.chat.id;

let registry = [];
try {
  const items = $('Read Registry').all();
  if (items && items.length > 0) {
    const first = items[0].json;
    if (Array.isArray(first)) registry = first;
    else if (Array.isArray(first.agents)) registry = first.agents;
    else registry = items.map(i => i.json);
  }
} catch(e) {}

let memory = [];
try {
  const items = $('Read Memory').all();
  if (items && items.length > 0) {
    const first = items[0].json;
    if (Array.isArray(first)) memory = first;
    else if (Array.isArray(first.memory)) memory = first.memory;
    else memory = items.map(i => i.json);
  }
} catch(e) {}

let profile = {};
try {
  const items = $('Read Profile').all();
  if (items && items.length > 0) profile = items[0].json || {};
} catch(e) {}

const userName = String(profile.display_name || '').trim();
const awaitingName = Boolean(profile.awaiting_name);
const profileExists = Boolean(profile.exists);

function cleanTextForPrompt(value) {
  return String(value || '')
    .replace(/[\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF\uFB50-\uFDFF\uFE70-\uFEFF\u0400-\u04FF\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF\uFB50-\uFDFF\uFE70-\uFEFF\u0400-\u04FF\u4E00-\u9FFF\u3400-\u4DBF\u3000-\u303F\uFF00-\uFFEF\u00C0-\u024F]/g, '')
    .replace(/\[out\]/gi, '').replace(/[\\*`#]/g, '')
    .replace(/(ОќОЎОЪ|ОЏОЋОА|ОЕОеОъОЋОў|ОќОЋОаОћ|ОъОќОЊОЎОЎОЪ|ОЉОЪ ОќОЋОаОћ|fuck|sex|porn)/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
}

const bannedAgentNames = new Set(['agent', 'snakecaseagent', 'snake_case_agent', 'snake_case_name', 'custom_task_agent', 'new_agent', 'helper', 'assistant']);

const activeAgents = registry
  .filter(a => (a.status || 'active') === 'active' && !bannedAgentNames.has(String(a.name || '').toLowerCase()))
  .sort((a, b) => {
    const scoreA = Number(a.score_avg ?? a.score ?? 0);
    const scoreB = Number(b.score_avg ?? b.score ?? 0);
    const usesA = Number(a.uses ?? 0);
    const usesB = Number(b.uses ?? 0);
    return (scoreB - scoreA) || (usesB - usesA);
  });

const agentList = activeAgents.slice(0, 8).length > 0
  ? activeAgents.slice(0, 8).map(a => `- ${a.name}: ${cleanTextForPrompt(a.description)} (ОъОфОљОЎОЮ Ою: ${cleanTextForPrompt(a.good_for || '')}; ОдОЎОЋОЪ: ${a.score_avg ?? a.score ?? 'ОЌОЊОЕ'}; ОЕОЎОъОЋОЕОЎОЮ: ${a.uses ?? 0})`).join('\n')
  : 'ОљОЎОЪ ОбОЊОЎОЎОЪ ОАОЋОЏОаОЎОЮ';

const recentMemory = memory.slice(-3)
  .map(m => `[${m.agent}] ${cleanTextForPrompt(m.task).substring(0, 120)}`)
  .join('\n') || 'None';

const conversationHistory = memory.slice(-3)
  .map(m => {
    const assistant = m.agent === 'chitchat' ? 'ОбОЋОќОе' : `ОбОЋОќОе [${m.agent}]`;
    return `ОъОЕОфОъОЕ: ${cleanTextForPrompt(m.task).substring(0, 180)}\n${assistant}: ${cleanTextForPrompt(m.result).substring(0, 220)}`;
  })
  .join('\n\n') || '';


const skipHistoryTasks = new Set(['ОћОЎ', 'ОћОЎОЎ', 'ОЕОюОЋОЮ', 'ОъОћ ОаОЕОъОб', 'ОъОћ ОДОЋОеОћ']);
const historyTaskWords = ['ОЉОљОЎОќОћ ОАОЋОЏОЪ', 'ОљОЎОќОћ ОАОЋОЏОЪ ОћОЕОфОъОЕ', 'ОљОЎОќОћ ОаОдОЎОњ ОћОЕОфОъОЕ', 'ОћОЎОАОўОЋОеОЎОЎОф ОАОЋОЏОаОЎОЮ', 'ОЕОЎОъОЋОЕОЎ ОАОЋОЏОаОЎОЮ', 'ОќОЎОЏОеОЋОЪ ОАОЋОЏОаОЎОЮ'];
const agentHistoryRows = [...memory].reverse()
  .filter(m => {
    const task = cleanTextForPrompt(m.task || '');
    const isHistoryTask = historyTaskWords.some(word => task.includes(word));
    return task && m.agent && !skipHistoryTasks.has(task) && !isHistoryTask;
  })
  .slice(0, 12)
  .map((m, index) => {
    const task = cleanTextForPrompt(m.task || '').substring(0, 180) || 'ОюОљ ОаОЕОъОеОћ ОъОЕОЎОъОћ';
    const agent = String(m.agent || 'ОюОљ ОЎОЊОЋОб').trim() || 'ОюОљ ОЎОЊОЋОб';
    const score = (m.score === null || m.score === undefined || m.score === '') ? 'ОљОЎОЪ' : String(m.score) + '/10';
    const time = String(m.timestamp || '').replace('T', ' ').substring(0, 16) || 'ОюОљ ОаОЕОъОе';
    const reason = cleanTextForPrompt(m.decision_reason || m.deductions || '').substring(0, 180) || 'ОюОљ ОаОЕОъОеОћ ОАОЎОЉОћ';
    return `${index + 1}. ОъОЕОЎОъОћ:
${task}
ОАОЋОЏОЪ:
${agent}
ОдОЎОЋОЪ:
${score}
ОАОЎОЉОћ:
${reason}
ОќОъОЪ:
${time}`;
  });

const agentHistory = agentHistoryRows.length
  ? `РћЈРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂ
РћЃ ОЕОЎОъОЋОЕОЎ ОАОЋОЏОаОЎОЮ ОъОћОќОЎОЏОеОЋОЪ
РћБРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂ
РћЃ ОъОЕОфОъОЕ:
РћЃ ${userName || 'ОъОЕОфОъОЕ'}
РћЃ
${agentHistoryRows.join('\n\n')}
РћЌРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂ`
  : `${userName || 'ОъОЕОфОъОЕ'}, ОљОЎОЪ ОбОЊОЎОЎОЪ ОЕОЎОъОЋОЕОЎ ОАОЋОЏОаОЎОЮ ОЕОъОЋОеОЎОЮ ОЉОќОЎОЏОеОЋОЪ ОћОљОЎОЕОЎ ОЕОюОџ.`;

const lastScored = [...memory].reverse().find(m => m.score !== null && m.score !== undefined);
const lastEvaluation = lastScored ? {
  task: lastScored.task || '',
  agent: lastScored.agent || '',
  score: lastScored.score,
  deductions: lastScored.deductions || 'ОюОљ ОаОЕОъОе ОцОЎОеОЋОў ОаОЎОЏОЋОЎОЎОЮ',
  result: cleanTextForPrompt(lastScored.result).substring(0, 500),
  timestamp: lastScored.timestamp || ''
} : null;

return [{ json: { userMessage, chatId, agents: activeAgents, agentList, recentMemory, conversationHistory, lastEvaluation, agentHistory, profile, userName, awaitingName, profileExists } }];

const data = $('Prepare Data').first().json;
const msg = String(data.userMessage || '').trim();
const lower = msg.toLowerCase();
const agents = Array.isArray(data.agents) ? data.agents : [];

const hasAny = (words) => words.some(w => lower.includes(w.toLowerCase()));
const exactCasual = ['ОћОЎ', 'ОћОЎОЎ', 'ОћОЎОЎОЎ', 'ОћОюОЋ', 'ОЕОюОЋОЮ', 'ОЉОЋОДОе ОўОЋОЉ', 'ОбОеОЉ ОўОЋОЉ', 'ОюОЎОюОћ ОўОЋОЉ', 'ОъОћ ОаОЕОъОб', 'ОъОћ ОДОЋОеОћ', 'ОъОћ ОћОъОдОЉ', 'ОфОЋОЊОћ', 'ОАОЉОЉОћ', 'ОљОЌОюОћ'];
const detailWords = ['ОцОЎОеОЋОў', 'ОфОЪ ОцОЎОеОЋОў', 'ОцОеОў', 'ОЕОюОЌ ОцОЎОеОЋОў', 'ОцОеОўОЎОЮ ОбОю ОћОдОЎОЋОЪ', 'ОюОъОћ ОћОдОЎОЋОЪ'];
const chitchatWords = ['ОъОЎ ОљОфОћ', 'ОбОќОеОћ', 'ОъОћ ОљОфОћ ОЎОЋОЊОб ОюОбОЕОЋОф'];
const codeWords = ['code', 'python', 'javascript', 'js', 'sql', 'html', 'css', 'react', 'bug', 'debug', 'ОЊОЎОЉОљОњ', 'ОДОЋОЊ', 'ОцОЋОаОДОдОЎОћ', 'ОАОДОеОЎОцОў', 'ОЕОњОЎОљОћ'];
const createAgentWords = ['ОдОЋОе ОюОЎ ОАОЋОЏОЪ', 'ОфОЎОдОЋОе ОюОЎ ОАОЋОЏОЪ', 'ОЉОаОћ ОюОЎ ОАОЋОЏОЪ', 'ОфОЉОаОћ ОюОЎ ОАОЋОЏОЪ', 'ОфОЏОЎОЪ ОюОЎ ОАОЋОЏОЪ', 'ОдОЋОе ОАОЋОЏОЪ', 'ОАОЋОЏОЪ ОЌОЊОЕ', 'ОаОдОЎОњ ОЌОЊОЕ'];
const historyWords = ['ОЉОљОЎОќОћ ОАОЋОЏОЪ', 'ОљОЎОќОћ ОАОЋОЏОЪ ОћОЕОфОъОЕ', 'ОљОЎОќОћ ОаОдОЎОњ ОћОЕОфОъОЕ', 'ОАОЋОЏОЪ ОћОЕОфОъОЕОф', 'ОаОдОЎОњ ОћОЕОфОъОЕОф', 'ОћОЎОАОўОЋОеОЎОЎОф ОАОЋОЏОаОЎОЮ', 'ОЕОЎОъОЋОЕОЎ ОАОЋОЏОаОЎОЮ', 'ОќОЎОЏОеОЋОЪ ОАОЋОЏОаОЎОЮ', 'ОАОЋОЏОЪ ОюОљОЎОќОЋ ОъОЕОЎОъОћ', 'ОаОдОЎОњ ОюОљОЎОќОЋ ОъОЕОЎОъОћ'];

function cleanName(value) {
  let text = String(value || '').trim();
  const match = text.match(/(?:ОДОЋОеОљОЎОЮ ОюОЎ|ОћОЕОЮ ОЕОюОЎ|ОљОаОЎ)\s+([^,.!?\n]+)$/i);
  if (match) text = match[1];
  text = text
    .replace(/^(ОДОЋОеОљОЎОЮ ОюОЎ|ОћОЕОЮ ОЕОюОЎ|ОљОаОЎ)\s+/i, '')
    .replace(/(?:^|\s)(ОфОЎОдОЋОе|ОдОЋОе|ОфОбОЕОћ|ОЉОаОћ|ОфОЉОаОћ|ОфОЏОЎОЪ|ОћОЏОЪ|ОдОеОЎОџ|ОеОЋОдОћ|ОАОЋОЏОЪ|ОаОдОЎОњ).*$/i, '')
    .replace(/[^\u0590-\u05FFa-zA-Z\s'-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (text.split(/\s+/).length > 3) return '';
  return text.slice(0, 40);
}

let action = 'create_agent';
let agent_name = null;
let direct_reply = null;
let userName = data.userName || '';
let requestMessage = msg;
let selectionReason = '';

if (!data.userName && !data.awaitingName) {
  action = 'ask_name';
  direct_reply = 'ОЉОеОЋОџ ОћОЉОљ. ОљОЎОџ ОДОЋОеОљОЎОЮ ОюОџ?\n\nОљОЌОеОЎ ОЕОфОЏОфОЋОЉ ОљОф ОћОЕОЮ ОЕОюОџ, ОљОќОЏОЋОе ОљОЋОфОЋ ОЋОљОцОаОћ ОљОюОЎОџ ОЉОЕОЮ ОЉОЕОЎОЌОЋОф ОћОЉОљОЋОф.';
} else if ((!data.userName && data.awaitingName) || /^\s*(ОДОЋОеОљОЎОЮ ОюОЎ|ОћОЕОЮ ОЕОюОЎ|ОљОаОЎ)\s+/i.test(msg)) {
  const extractedName = cleanName(msg);
  const inlineRequest = (() => {
    const raw = msg.replace(/^\s*(ОДОЋОеОљОЎОЮ ОюОЎ|ОћОЕОЮ ОЕОюОЎ|ОљОаОЎ)\s+/i, '').trim();
    const marker = raw.search(/\s(ОдОЋОе|ОфОЎОдОЋОе|ОфОбОЕОћ|ОЉОаОћ|ОфОЉОаОћ|ОфОЏОЎОЪ|ОћОЏОЪ|ОдОеОЎОџ|ОеОЋОдОћ)\s/i);
    if (marker > 0) return raw.slice(marker).trim();
    return '';
  })();
  if (extractedName && inlineRequest && inlineRequest.split(/\s+/).filter(Boolean).length >= 3) {
    action = 'create_agent';
    userName = extractedName;
    requestMessage = inlineRequest;
    direct_reply = null;
  } else if (extractedName) {
    action = 'save_name';
    userName = extractedName;
    direct_reply = `ОаОбОЎОЮ ОъОљОЋОЊ, ${userName}.\n\nОъОбОЏОЕОЎОЋ ОљОцОаОћ ОљОюОЎОџ ОЉОЕОЮ ОћОќОћ. ОљОЮ ОЏОфОЉОф ОњОЮ ОЉОДОЕОћ ОЉОљОЋОфОћ ОћОЋОЊОбОћ, ОЕОюОЌ ОљОЋОфОћ ОЕОЋОЉ ОЉОЕОЋОеОћ ОЌОЊОЕОћ ОЋОљОўОцОю ОЉОћ ОъОЎОЊ.`;
  } else {
    action = 'ask_name';
    direct_reply = 'ОюОљ ОћОдОюОЌОфОЎ ОюОћОЉОЎОЪ ОъОћ ОћОЕОЮ ОЉОюОЉОЊ. ОЏОфОЋОЉ ОеОД ОљОф ОћОЕОЮ ОЕОюОџ, ОюОъОЕОю: ОбОЋОцОе';
  }
} else {
  const wordCount = msg.split(/\s+/).filter(Boolean).length;
  const isShortCasual = wordCount <= 3 && (exactCasual.includes(lower) || hasAny(exactCasual));
  const asksForScoreDetails = hasAny(detailWords);
  const asksForAgentHistory = hasAny(historyWords);

  if (asksForAgentHistory) {
    action = 'chitchat';
    direct_reply = data.agentHistory || `${data.userName || 'ОъОЕОфОъОЕ'}, ОљОЎОЪ ОбОЊОЎОЎОЪ ОЕОЎОъОЋОЕОЎ ОАОЋОЏОаОЎОЮ ОЕОъОЋОеОЎОЮ ОЉОќОЎОЏОеОЋОЪ ОћОљОЎОЕОЎ ОЕОюОџ.`;
  } else if (hasAny(createAgentWords)) {
    action = 'create_agent';
  } else if (asksForScoreDetails) {
    action = 'chitchat';
    const ev = data.lastEvaluation;
    if (ev) {
      direct_reply = `РћЈРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂ
РћЃ ОцОЎОеОЋОў ОдОЎОЋОЪ ОљОЌОеОЋОЪ
РћБРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂ
РћЃ ОъОЕОфОъОЕ:
РћЃ ${data.userName}
РћЃ
РћЃ ОАОЋОЏОЪ:
РћЃ ${ev.agent}
РћЃ
РћЃ ОдОЎОЋОЪ:
РћЃ ${ev.score}/10
РћЃ
РћЃ ОАОЎОЉОћ:
РћЃ ${ev.deductions}
РћЃ
РћЃ ОъОЕОЎОъОћ:
РћЃ ${ev.task}
РћЌРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂРћЂ`;
    } else {
      direct_reply = `${data.userName}, ОљОЎОЪ ОбОЊОЎОЎОЪ ОдОЎОЋОЪ ОЕОъОЋОе ОЉОќОЎОЏОеОЋОЪ ОћОљОЎОЕОЎ ОЕОюОџ.`;
    }
  } else if (!msg || isShortCasual || hasAny(chitchatWords)) {
    action = 'chitchat';
    if (isShortCasual) {
      direct_reply = `${data.userName || 'ОЕОюОЋОЮ'}, ОЕОюОЋОЮ. ОљОЎОџ ОљОцОЕОе ОюОбОќОЋОе ОюОџ ОбОЏОЕОЎОЋ?`;
    }
  } else if (hasAny(codeWords) && agents.some(a => a.name === 'code_helper')) {
    action = 'use_agent';
    agent_name = 'code_helper';
  } else {
    const tokens = lower
      .replace(/[^a-z0-9Ољ-Оф_\s]/gi, ' ')
      .split(/\s+/)
      .filter(t => t.length >= 3);

    const agentTimes = agents
      .map(a => Date.parse(a.updated_at || a.last_used || a.created_at || ''))
      .filter(Number.isFinite);
    const newestTime = agentTimes.length ? Math.max(...agentTimes) : Date.now();
    const oldestTime = agentTimes.length ? Math.min(...agentTimes) : newestTime;
    const timeSpan = Math.max(1, newestTime - oldestTime);

    const candidates = [];
    for (const agent of agents) {
      const haystack = [agent.name, agent.description, agent.good_for].join(' ').toLowerCase();
      let matchScore = 0;
      const matchedTokens = [];
      for (const token of tokens) {
        if (haystack.includes(token)) {
          matchScore += 1;
          matchedTokens.push(token);
        }
      }
      if (matchScore <= 0) continue;

      const agentScore = Number(agent.score_avg ?? agent.score ?? 0) || 0;
      const quality = Math.min(agentScore, 10) / 10;
      const uses = Number(agent.uses ?? 0) || 0;
      const updatedMs = Date.parse(agent.updated_at || agent.last_used || agent.created_at || '') || oldestTime;
      const recency = Math.max(0, Math.min(1, (updatedMs - oldestTime) / timeSpan));
      const freshImprovedBonus = recency >= 0.65 && agentScore >= 8 ? 0.55 : (recency >= 0.65 && agentScore >= 7 ? 0.25 : 0);
      const finalScore = (matchScore * 1.35) + (quality * 0.95) + (recency * 0.55) + (Math.min(uses, 12) / 120) + freshImprovedBonus;

      candidates.push({
        agent,
        matchScore,
        matchedTokens: [...new Set(matchedTokens)].slice(0, 5),
        agentScore,
        uses,
        updatedMs,
        recency,
        finalScore
      });
    }

    candidates.sort((a, b) =>
      (b.finalScore - a.finalScore) ||
      (b.agentScore - a.agentScore) ||
      (b.updatedMs - a.updatedMs)
    );

    let best = candidates[0] || null;
    if (best) {
      for (const candidate of candidates.slice(1)) {
        const closeMatch = candidate.matchScore >= best.matchScore - 0.5;
        const fresherAndNoWorse = candidate.updatedMs > best.updatedMs && candidate.agentScore >= best.agentScore - 0.25;
        const closeEnough = candidate.finalScore >= best.finalScore - 0.35;
        if (closeMatch && fresherAndNoWorse && closeEnough) {
          best = candidate;
        }
      }
    }

    if (best && best.finalScore >= 1.85 && best.matchScore >= 1) {
      action = 'use_agent';
      agent_name = best.agent.name;
      const updated = best.agent.updated_at || best.agent.last_used || best.agent.created_at || 'ОюОљ ОаОЕОъОе';
      const freshness = best.recency >= 0.65 ? 'ОбОЊОЏОаОЎ ОЎОЌОАОЎОф' : 'ОЋОфОЎОД ОљОЉОю ОбОЊОЎОЎОЪ ОъОфОљОЎОЮ';
      selectionReason = `ОаОЉОЌОе ${agent_name} ОЏОЎ ОћОЋОљ ОъОфОљОЎОЮ ОюОъОЎОюОЎОЮ: ${best.matchedTokens.join(', ') || 'ОћОфОљОъОћ ОЏОюОюОЎОф'}. ОдОЎОЋОЪ: ${best.agentScore || 'ОЌОЊОЕ'}, ОЕОЎОъОЋОЕОЎОЮ: ${best.uses}, ОбОЊОЏОЋОЪ ОљОЌОеОЋОЪ: ${String(updated).replace('T', ' ').substring(0, 16)}. ОћОбОЊОцОћ: ${freshness}; ОАОЋОЏОЪ ОЌОЊОЕ ОЎОЋОфОе ОбОЮ ОдОЎОЋОЪ ОЊОЋОъОћ ОљОЋ ОњОЉОЋОћ ОъОДОЉОю ОДОЊОЎОъОЋОф.`;
    }
  }
}

const decision_reason = action === 'use_agent'
  ? (selectionReason || `ОаОЉОЌОе ${agent_name} ОюОцОЎ ОћОфОљОъОћ, ОдОЎОЋОЪ, ОбОЊОЏОаОЎОЋОф ОЋОЕОЎОъОЋОЕОЎОЮ ОДОЋОЊОъОЎОЮ.`)
  : (action === 'create_agent'
