  if (/ОъОЋОЊОЋОю|module/.test(t)) parts.push('module');
  if (/ОаОфОЋОа|data|db|database/.test(t)) parts.push('data');
  if (/front|frontend|ui|ОъОАОџ|ОъОъОЕОД/.test(t)) parts.push('frontend');
